import { NextResponse } from "next/server";import { buildArticleExport,ExportNotReadyError } from "@/modules/article-export/serializer";
export async function GET(req:Request,{params}:{params:Promise<{articleId:string}>}){const secret=process.env.WEBSITE_IMPORT_API_KEY;if(!secret||req.headers.get("authorization")!==`Bearer ${secret}`)return NextResponse.json({error:"Unauthorized"},{status:401});const articleId=Number((await params).articleId);try{return NextResponse.json(await buildArticleExport(articleId),{headers:{"Cache-Control":"private, no-store","X-Export-Schema-Version":"1.0"}})}catch(e){return NextResponse.json({error:e instanceof Error?e.message:"Not found"},{status:e instanceof ExportNotReadyError?409:404})}}
